const OPTIONS_DESCRIPTIONS = {};
function formatNumber(num) {
  return Number.isInteger(num) ? num.toString() : num.toFixed(2);
}
function handleOfferSelection(offer, offerCard) {
  if (offer.state === "CHOSEN") offerCard.classList.add("chosen");
}
function handleSelectButton(offer, selectButton) {
  selectButton.addEventListener("click", () => {
    appsmith.triggerEvent("offerChosen", {
      offer
    });
  });
}
function getSvgStringFromObj(svgObj) {
  const {
    xmlns,
    width,
    height,
    viewBox,
    fill,
    path
  } = svgObj;
  return `<svg xmlns="${xmlns}" width="${width}" height="${height}" viewBox="${viewBox}" fill="${fill}">
		<path d="${path.d}" fill="${path.fill}" />
			</svg>`;
}
;
function handleBooleanDisplay(value) {
  const {
    tickNoSVG,
    tickYesSVG
  } = appsmith.model.icons;
  const TickYesIcon = getSvgStringFromObj(tickYesSVG);
  const TickNoIcon = getSvgStringFromObj(tickNoSVG);
  return value === "true" ? TickYesIcon : TickNoIcon;
}
function handleNumberDisplay(value, unit) {
  const realValue = formatNumber(parseInt(value) / 100);
  return `${realValue}\u00a0${unit}`;
}
function handleStringDisplay(value, responses) {
  if (!responses) return value;
  const responsesMap = JSON.parse(responses);
  return responsesMap[value].text ?? value;
}
function handleHeaderDisplay(offer, offerLogoElement, offerPriceElement, offerSavingsElement) {
  if (!offer.savings) {
    if (offerSavingsElement) offerSavingsElement.remove();
    offerPriceElement.style.marginBottom = 0;
  } else {
    if (offerSavingsElement) offerSavingsElement.style.color = getSavingsColor(offer);
  }
  offerLogoElement.style.backgroundColor = offer.partner.color;
}
function getSavingsColor(offer) {
  return offer.savingsTextColor;
}
function getOptionValue(type, unit, value, responses) {
  if (!value) return "-";
  const handlers = {
    default: () => value,
    boolean: () => handleBooleanDisplay(value),
    number: () => handleNumberDisplay(value, unit),
    string: () => handleStringDisplay(value, responses)
  };
  return (handlers[type] || handlers.default)();
}
function generateFeatures(options) {
  let featureHTML = "";
  options.forEach(({
    type,
    unit,
    title,
    label,
    value,
    responses,
    description
  }) => {
    if (!OPTIONS_DESCRIPTIONS[label]) OPTIONS_DESCRIPTIONS[label] = description;
    featureHTML += `
        <div class="feature">
          <b class="feature-title">${title}</b>
          <b class="feature-value">${getOptionValue(type, unit, value, responses)}</b>
        </div>
      `;
  });
  return featureHTML;
}
function getFeaturedOptionsToDisplay(features, shownOptions) {
  return features.flatMap(offerOptions => offerOptions.options.filter(option => shownOptions.includes(option.label)));
}
function generateFeatureCategories(features) {
  const shownOptions = appsmith.model.featuredOffersShownOptions;
  return `
    <div class="feature-list">
      ${generateFeatures(getFeaturedOptionsToDisplay(features, shownOptions))}
    </div>
  `;
}
function generateOfferCard(offer) {
  return `
    <div class="card_title">
      <span>${offer.header_text}</span>
    </div>
    <div class="offer_card_inner_div">
      <img src="${offer.partner.logo}" />
      <p class="insurer-name">${offer.partner.name}</p>
      <p class="formula-name">${offer.name}</p>
      <div class="price-box" id="first">
				<p class="offer-price">
  				${offer.is_estimation ? "tarif sur devis" : `<b>${offer.price}€</b> /mois`}
				</p>
      </div>
			${!offer.is_estimation ? `
				<div class="price-box">
        	<p class="offer-savings"><b>${offer.savings}€</b> ${offer.savingsUnit}</p>
      	</div>` : ""}
      <div class="features">
        ${generateFeatureCategories(offer.options)}
      </div>
      <div class="buttons">
        <button class="btn btn-select">Voir l'offre</button>
      </div>
    </div>
  `;
}
function generateOffers(offers) {
  const container = document.getElementById("offers-container");
  container.innerHTML = "";
  offers.forEach((offer, index) => {
    const offerCard = document.createElement("div");
    offerCard.innerHTML = generateOfferCard(offer);
    offerCard.className = "offer-card";
    offerCard.id = `offer${index}`;
    const offerLogoElement = offerCard.querySelector("img");
    const offerPriceElement = offerCard.querySelector(".offer-price");
    const offerSavingsElement = !offer.is_estimation ? offerCard.querySelector(".offer-savings") : null;
    const selectButton = offerCard.querySelector(".btn-select");
    handleHeaderDisplay(offer, offerLogoElement, offerPriceElement, offerSavingsElement);
    handleOfferSelection(offer, offerCard);
    handleSelectButton(offer, selectButton);
    container.appendChild(offerCard);
  });
}
function renderPage() {
  generateOffers(appsmith.model.offers);
  const overlay = document.querySelector(".info-overlay");
  const closeButton = overlay.querySelector(".close-info");
  closeButton.addEventListener("click", () => {
    overlay.classList.remove("active");
  });
  overlay.addEventListener("click", e => {
    if (e.target === overlay) overlay.classList.remove("active");
  });
}
appsmith.onReady(() => {
  if (Object.keys(appsmith.model).length > 0) renderPage();
});
appsmith.onModelChange(newModel => {
  if (Object.keys(newModel).length > 0) renderPage();
});

